#include "Helper.hpp"#include <iostream>#include <fstream>#include <string>#include <vector>#include <map>int Read_CSV(std::string file_path, std::map <int, std::vector<Vertex>>& poly){    std::ifstream ifs(file_path);    if(!ifs.is_open()){        std::cerr << "No such path exists\n";        ifs.close();        return 0;    }    std::string line{};    //Skip first line    std::getline(ifs, line);    while(std::getline(ifs, line)){        if(line.empty()){            break;        }        std::size_t pos{};        std::size_t cur_pos{};        int var = 0;        int ring_id{};       // int vertex_id{};        Vertex v;        while((pos = line.find(",", cur_pos)) != std::string::npos){            switch(var){                case 0:                //Ring Id                ring_id = std::stoi(line.substr(0, pos));                //std::cout << "Ring Id: " << ring_id;                break;                case 1:                //vertex_id = std::stoi(line.substr(cur_pos, pos - cur_pos));                //std::cout << " Vertex Id: " << vertex_id;                break;                case 2:                v.x = std::stof(line.substr(cur_pos, pos - cur_pos));                //std::cout << " X value: " << v.x;                break;            }            var++;            cur_pos = pos + 1;        }        v.y = std::stof(line.substr(cur_pos, line.size() - cur_pos));        //std::cout << " Y Value: " << v.y << std::endl;                poly[ring_id].emplace_back(v);                            }    ifs.close();    return 1;}void Print_Poly(std::string file_path, std::map <int, std::vector<Vertex>>const & poly){    std::ofstream ofs(file_path);    if(!ofs.is_open()){        std::cerr << "Output Check File cannot be opened!!/n";        ofs.close();        return;    }    for(auto const &[key, val] : poly){        for(std::size_t i = 0; i < val.size(); i++){            ofs << key << "," << i << "," << val[i].x<< "," << val[i].y;            if(i < val.size() - 1){                ofs << std::endl;            }        }    }    ofs.close();}